    // {*, *, 1}
    sendRouteTableInit(3, 0, 0, 0, 1);

    // For 4:
    // {*, 1, 1}
    sendRouteTableInit(4, 0, 0, 1, 1);
    // {*, 2, 2}
    sendRouteTableInit(4, 1, 0, 2, 2);
